import "sort"

func solve(nums []int64, k int64) int64 {
    sort.Slice(nums, func(i, j int) bool { return nums[i] < nums[j] })
    maxLen := 1
    n := len(nums)
    for i := 0; i < n; i++ {
        target := nums[i] * k
        low := i
        high := n - 1
        j := i
        for low <= high {
            mid := (low + high) / 2
            if nums[mid] <= target {
                j = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        currentLen := j - i + 1
        if currentLen > maxLen {
            maxLen = currentLen
        }
    }
    return int64(n - maxLen)
}
